<template>
    <div id="submitpage">
        <loadings :isLoading="settings.base.beforeLoad? 1: 0"></loadings>
        <div v-if="!settings.base.beforeLoad" >
            <div id="editor-container" class="immersive-container">
                <top-side
                        v-bind:class="{'problem-only': settings.view.problemOpen && !settings.view.editOpen, 'editor-only': !settings.view.problemOpen && settings.view.editOpen}">
                    <slide-curtain style="display: none; height: 658.4px;">
                    </slide-curtain>
                    <left-side style="width: 49.82vw;">
                        <div v-bind:class="{'left-side-pre': true, 'container-pro': settings.view.problemOpen && !settings.view.editOpen}">
                            <div class="prob-header animated pre-animated cm-performance-optimistic fadeInLeft">
                                <button class="btn btn-outline-secondary" id="backBtn"
                                        v-bind:onclick="'window.location.href = \'/problem.html?pid=' + encodeURIComponent(settings.problem.pid)+'\''">
                                    <i class="fa fa-hand-o-left" aria-hidden="true"></i>
                                    Back
                                </button>
                                <info-badge data-toggle="tooltip" data-placement="top" title=""
                                            data-original-title="AC Rate">
                                    <i class="fa fa-star" aria-hidden="true"></i>
                                    {{(result.problemForm.problem.submitStatistics.allSubmitTimes == 0)? '-&#45;&#45;':
                                    (100*result.problemForm.problem.submitStatistics.acSubmitTimes/result.problemForm.problem.submitStatistics.allSubmitTimes).toFixed(2)
                                    + "%"}}
                                </info-badge>
                                <info-badge data-toggle="tooltip" data-placement="top" title=""
                                            data-original-title="Time Limit">
                                    <i class="fa fa-clock-o" aria-hidden="true"></i>
                                    {{result.problemForm.problem.timeLimit}}ms
                                </info-badge>
                                <info-badge data-toggle="tooltip" data-placement="top" title=""
                                            data-original-title="Memory Limit">
                                    <i class="fa fa-cog" aria-hidden="true"></i>
                                    {{(result.problemForm.problem.memoryLimit / 1024).toFixed(0)}}KB
                                </info-badge>
                                <info-badge v-if="result.problemForm.problem.isSpj" style="color: red">
                                    Special Judge
                                </info-badge>
                            </div>
                            <div class="animated pre-animated cm-performance-optimistic cm-delay fadeInLeft">
                                <fresh-container>
                                    <div style="text-align: center;font-family: Consolas;white-space: pre;">
                                        <h3 style="">{{result.problemForm.problem.problemId + ': ' + result.problemForm.problem.title}}</h3>
                                    </div>
                                    <div style="margin-top: 1rem; font-size: 17px;">
                                        <i aria-hidden="true" class="fa fa-bars"></i>
                                        <span> Problem Information</span>
                                    </div>
                                    <div class="problem">
                                        <div class="card">
                                            <div class="card-header" style="color: black;">
                                                <span>Problem Description</span>
                                            </div>
                                            <div class="card-body">
                                                <span style="white-space: pre;" v-html="result.problemForm.problem.problemDescribe"></span>
                                            </div>
                                        </div>
                                        <div class="card">
                                            <div class="card-header" style="color: black;">
                                                <span>Input Description</span>
                                            </div>
                                            <div class="card-body">
                                                <span style="white-space: pre;" v-html="result.problemForm.problem.inputDescribe"></span>
                                            </div>
                                        </div>
                                        <div data-v-8b7d93b8="" class="card">
                                            <div class="card-header" style="color: black;">
                                                <span>Output Description</span>
                                            </div>
                                            <div class="card-body">
                                                <span style="white-space: pre;" v-html="result.problemForm.problem.outputDescribe"></span>
                                            </div>
                                        </div>
                                        <template v-for="(sample,index) in result.problemForm.problem.sampleIO">
                                            <div class="double-card" v-bind:key="key">
                                                <div class="card" style="width: 48%; float: left;">
                                                    <div class="card-header" style="color: black;">
                                                <span>
                                                    Sample Input&nbsp;{{index+1}}&nbsp;
                                                    <a v-if="settings.problem.copy.id == index && settings.problem.copy.ing == true && settings.problem.copy.type == 0"
                                                       href="javascript:void(0)">
                                                        <i class="fa fa-check-circle" aria-hidden="true"></i>
                                                    </a>
                                                    <a v-else href="javascript:void(0)"
                                                       @click="handleCopy(sample.sample_I, $event, index, 0)">
                                                    <i class="fa fa-files-o" aria-hidden="true"></i>
                                                </a>
                                                </span>
                                                    </div>
                                                    <div class="card-body">
                                                <span style="white-space: pre;" v-bind:id="'sampleinput'+index"
                                                      class="sampledata">{{sample.sample_I}}</span>
                                                    </div>
                                                </div>
                                                <div class="card" style="width: 48%; float: right;">
                                                    <div class="card-header" style="color: black;">
                                                <span>
                                                    Sample Output&nbsp;{{index+1}}&nbsp;
                                                    <a v-if="settings.problem.copy.id == index && settings.problem.copy.ing == true && settings.problem.copy.type == 1"
                                                       href="javascript:void(0)">
                                                        <i class="fa fa-check-circle" aria-hidden="true"></i>
                                                    </a>
                                                    <a v-else href="javascript:void(0)"
                                                       @click="handleCopy(sample.sample_O, $event, index, 1)">
                                                        <i class="fa fa-files-o" aria-hidden="true"></i>
                                                    </a>
                                                </span>
                                                    </div>
                                                    <div class="card-body">
                                                <span style="white-space: pre;" v-bind:id="'sampleoutput'+index"
                                                      class="sampledata">{{sample.sample_O}}</span>
                                                    </div>
                                                </div>
                                                <div style="clear: both;"></div>
                                            </div>
                                        </template>
                                    </div>
                                </fresh-container>
                            </div>
                        </div>

                    </left-side>
                    <middle-slider>
                    </middle-slider>
                    <right-side
                            style="width: 49.82vw;padding-bottom: 10px;padding-top: 10px;padding-right:5px;background-color: black">
                        <!--<button class="btn btn-secondary" style="margin: 8px;color:white">555</button>-->
                        <editor theme="twilight" v-model="forms.solutionForm.code" lang="c_cpp" height="100%"
                                @init="initEditor"
                                :options="settings.editor"></editor>
                    </right-side>
                </top-side>
                <bottom-side>
                    <div>
                        <button type="button" v-bind:class="{'btn':true, 'btn-secondary': true, 'cm-active': settings.view.problemOpen}"
                                id="problemBtn" @click="toggltProblemButton">
                            <i class="fa fa-book fa-fw" aria-hidden="true"></i>
                        </button>
                        <button type="button" v-bind:class="{'btn':true, 'btn-secondary': true, 'cm-active': settings.view.editOpen}"
                                id="editorBtn" @click="toggltEditButton">
                            <i class="fa fa-pencil-square-o fa-fw" aria-hidden="true"></i></button>
                        <button type="button" class="btn btn-secondary" id="historyBtn">
                            <i class="fa fa-history fa-fw" aria-hidden="true"></i>
                            History
                        </button>
                    </div>
                    <div>
                        <div class="btn-group dropup">
                            <button type="button" class="btn btn-secondary dropdown-toggle" id="cur_lang_selector"
                                    data-toggle="dropdown" aria-haspopup="true" aria-expanded="false">
                                <template v-if="forms.solutionForm.lang == GLOBAL.OJ_LANG_C">
                                    <i class="devicon-c-plain colored"></i> C
                                </template>
                                <template v-else-if="forms.solutionForm.lang == GLOBAL.OJ_LANG_CPLUS">
                                    <i class="devicon-cplusplus-plain colored"></i> C++
                                </template>
                                <template v-else-if="forms.solutionForm.lang == GLOBAL.OJ_LANG_CPLUS11">
                                    <i class="devicon-cplusplus-plain colored"></i> C++11
                                </template>
                            </button>
                            <div class="dropdown-menu cm-scrollable-menu">
                                <button class="dropdown-item lang-selector" @click="switchLang(GLOBAL.OJ_LANG_C)"><i
                                        class="devicon-c-plain colored"></i> C
                                </button>
                                <button class="dropdown-item lang-selector" @click="switchLang(GLOBAL.OJ_LANG_CPLUS)"><i
                                        class="devicon-cplusplus-plain colored"></i> C++
                                </button>
                                <button class="dropdown-item lang-selector" @click="switchLang(GLOBAL.OJ_LANG_CPLUS11)"><i
                                        class="devicon-cplusplus-plain colored"></i> C++11
                                </button>
                                <!--<button class="dropdown-item lang-selector" data-coid="3" data-comp="java" data-lang="java"-->
                                <!--data-lcode="java"><i class="devicon-java-plain colored"></i> Java-->
                                <!--</button>-->
                                <!--<button class="dropdown-item lang-selector" data-coid="32" data-comp="python"-->
                                <!--data-lang="python" data-lcode="py2"><i class="devicon-python-plain colored"></i>-->
                                <!--Python 2.7-->
                                <!--</button>-->
                                <!--<button class="dropdown-item lang-selector" data-coid="33" data-comp="python"-->
                                <!--data-lang="python" data-lcode="py3"><i class="devicon-python-plain colored"></i>-->
                                <!--Python 3.7-->
                                <!--</button>-->
                                <!--<button class="dropdown-item lang-selector" data-coid="121" data-comp="php" data-lang="php"-->
                                <!--data-lcode="php7"><i class="devicon-php-plain colored"></i> PHP 7.3-->
                                <!--</button>-->
                                <!--<button class="dropdown-item lang-selector" data-coid="122" data-comp="javascript"-->
                                <!--data-lang="javascript" data-lcode="jsc"><i-->
                                <!--class="devicon-javascript-plain colored"></i> Javascript-->
                                <!--</button>-->
                            </div>
                            <button type="button" class="btn btn-primary" id="submitBtn" @click="postSolutionForm">
                                <i class="fa fa-paper-plane fa-fw" aria-hidden="true"></i>
                                Submit Code
                            </button>
                            <button type="button" class="btn btn-primary"
                                    id="resultBtn">
                                <i v-if="result.solutionForm.result == -1" class="fa fa-dot-circle-o fa-fw" aria-hidden="true"
                                   style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_WAITING"
                                   class="fa fa-spin fa-cog fa-fw " aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_COMPILING"
                                   v-bind:class="'fa fa-spin fa-cog fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_RUNNING_JUDGING"
                                   v-bind:class="'fa fa-spin fa-cog fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_JUDGING"
                                   v-bind:class="'fa fa-spin fa-cog fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_ACCEPTED"
                                   v-bind:class="'fa fa-check fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_COMPILATION_ERROR"
                                   v-bind:class="'fa fa-exclamation-triangle fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_SYSTEM_ERROR"
                                   v-bind:class="'fa fa-times fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_WRONG_ANSWER"
                                   v-bind:class="'fa fa-times fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_RUNTIME_ERROR"
                                   v-bind:class="'fa fa-times fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_PRESENTATION_ERROR"
                                   v-bind:class="'fa fa-times fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_TIME_LIMIT_EXCEEDED"
                                   v-bind:class="'fa fa-times fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_MEMORY_LIMIT_EXCEEDED"
                                   v-bind:class="'fa fa-times fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                                <i v-else-if="result.solutionForm.result == GLOBAL.OJ_RESULT_OUTPUT_LIMIT_EXCEEDED"
                                   v-bind:class="'fa fa-times fa-fw '+GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(result.solutionForm.result)"
                                   aria-hidden="true" style="font-size: 20px"></i>
                            </button>

                        </div>
                    </div>
                </bottom-side>
            </div>
        </div>

    </div>
</template>

<script>
    /* eslint vue/valid-v-for: "off"*/
    import Loadings from "@/components/loading/loading";
    import fun from '@/assets/js/OJFunction'

    export default {
        data() {
            return {
                settings: {
                    base:{
                        belong: 'submit',
                        isLogin: false,
                        beforeLoad: true,
                        user: new Object(),
                    },
                    problem:{
                        pid: 0,
                        copy: {
                            id: "",
                            ing: false,
                            type: "",
                        },
                    },
                    editor: {  // 设置代码编辑器的样式
                        enableBasicAutocompletion: true,
                        enableSnippets: true,
                        enableLiveAutocompletion: true,
                        tabSize: 4,
                        fontSize: 18,
                        showPrintMargin: false   //去除编辑器里的竖线
                    },
                    view:{
                        problemOpen: true,
                        editOpen: true
                    }
                },
                forms:{
                    problemForm:{
                        pid: 0
                    },
                    solutionForm:{
                        pid: 0,
                        code: "",
                        lang: 0,
                    }
                },
                result:{
                    solutionForm:{
                        sid: 0,
                        result: -1,
                    },
                    problemForm:{
                        problem: new Object(),
                    }
                },
            }
        },
        methods: {
            initEditor: function () {
                require('brace/ext/language_tools')
                require('brace/mode/c_cpp');
                require('brace/theme/twilight');
            },
            handleCopy(text, event, i, j) {
                fun.handleClipboard(text, event)
                this.settings.problem.copy.id = i;
                this.settings.problem.copy.type = j;
                this.settings.problem.copy.ing = true;
                var _this = this;
                setTimeout(function () {
                    _this.settings.problem.copy.ing = false;
                }, 500)
            },
            toggltProblemButton: function () {
                if (!this.settings.view.problemOpen) this.settings.view.problemOpen = true;
                else if (this.settings.view.editOpen) this.settings.view.problemOpen = false;
            },
            toggltEditButton: function () {
                if (!this.settings.view.editOpen) this.settings.view.editOpen = true;
                else if (this.settings.view.problemOpen) this.settings.view.editOpen = false;
            },
            switchLang: function (l) {
                this.forms.solutionForm.lang = l;
            },
            postSolutionForm: function () {
                this.result.solutionForm.result = this.GLOBAL.OJ_RESULT_WAITING;
                this.result.solutionForm.sid = 0;
                var _this = this
                window.axios.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/solution/submit', fun.stringify(_this.forms.solutionForm), {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                }).then(function (res) {
                    let data = res.data
                    var error_type = data.OJ_ERROR_TYPE;
                    if (error_type == _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        _this.result.solutionForm.sid = data.OJ_SOLUTION_ID;
                        _this.refreshResult();
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_NOT_LOGIN) {
                        window.location.href = '/loginpage.html';
                    }
                    // console.log(datas)
                }).catch(function (error) {
                    console.log(error)
                })

                // this.$http.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/submitcode',
                //     {
                //         pid: this.settings.problem.pid,
                //         lang: this.forms.solutionForm.lang,
                //         code: this.forms.solutionForm.code
                //     }, {
                //         emulateJSON: true,
                //         headers: {
                //             OJ_ACCESS_TOKEN: this.settings.access_token,
                //             OJ_REFRESH_TOKEN: this.settings.refresh_token
                //         }
                //     }).then(function (res) {
                //     var error_type = res.body.OJ_ERROR_TYPE;
                //     if (error_type == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                //         this.result.solutionForm.sid = res.body.OJ_SOLUTION_ID;
                //         this.refreshResult();
                //     } else if (error_type == this.GLOBAL.OJ_ERROR_NOT_LOGIN) {
                //         window.location.href = '/loginpage.html';
                //     }
                // }, function () {
                //     console.log('请求失败处理');
                // });
            },
            refreshResult: function () {
                if (this.result.solutionForm.sid != 0 && (this.result.solutionForm.result == -1
                    || this.result.solutionForm.result == this.GLOBAL.OJ_RESULT_WAITING
                    || this.result.solutionForm.result == this.GLOBAL.OJ_RESULT_COMPILING
                    || this.result.solutionForm.result == this.GLOBAL.OJ_RESULT_RUNNING_JUDGING
                    || this.result.solutionForm.result == this.GLOBAL.OJ_RESULT_JUDGING)) {
                    var _this = this
                    window.axios.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/solution/get', fun.stringify({
                        sid: _this.result.solutionForm.sid,
                    }), {
                        headers: {
                            OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                        }
                    }).then(function (res) {
                        let data = res.data
                        var error_type = data.OJ_ERROR_TYPE;
                        if (error_type == _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                            _this.result.solutionForm.result = data.OJ_RESULT;
                            setTimeout(function () {
                                _this.refreshResult();
                            }, 2000)
                        } else if (error_type == _this.GLOBAL.OJ_ERROR_NOT_LOGIN) {
                            window.location.href = '/loginpage.html';
                        }
                        // console.log(datas)
                    }).catch(function (error) {
                        console.log(error)
                    })
                    // this.$http.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/solution/get',
                    //     {
                    //         sid: this.result.solutionForm.sid,
                    //     }, {
                    //         emulateJSON: true,
                    //         headers: {
                    //             OJ_ACCESS_TOKEN: this.settings.access_token,
                    //             OJ_REFRESH_TOKEN: this.settings.refresh_token
                    //         }
                    //     }).then(function (res) {
                    //     console.log(res.body)
                    //     var error_type = res.body.OJ_ERROR_TYPE;
                    //     if (error_type == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                    //         this.result.solutionForm.result = res.body.OJ_RESULT;
                    //
                    //         var _this = this
                    //         setTimeout(function () {
                    //             _this.refreshResult();
                    //         }, 2000)
                    //     } else if (error_type == this.GLOBAL.OJ_ERROR_NOT_LOGIN) {
                    //         window.location.href = '/loginpage.html';
                    //     }
                    // }, function () {
                    //     console.log('请求失败处理');
                    // });
                }

            },
            async refresh(){
                var _this = this
                setTimeout(async function () {
                    // console.log(1)
                    let data = await fun.refresh();
                    if (data.OJ_ERROR_TYPE == _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        _this.settings.base.isLogin = true;
                        _this.settings.base.userInfo = data.OJ_USER_INFO;
                    }else{
                        window.location.href = '/loginpage.html';
                    }
                    _this.refresh()
                }, 1000*60*20)
            },
            identify: async function () {
                let data = await fun.idenfity();
                this.$i18n.locale = data.OJ_LANGUAGE_TYPE;
                if (data.OJ_ERROR_TYPE == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                    this.settings.base.isLogin = true;
                    this.settings.base.userInfo = data.OJ_USER_INFO;
                }
                this.refresh()
                return data;
            },
            searchProblem(){
                var _this = this
                return window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/problem/get', fun.stringify(_this.forms.problemForm), {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                })
            }
        },
        components: {
            editor: require("vue2-ace-editor"),
            Loadings,
        },
        name: "submitpage",
        async created() {
            await this.identify();
            
            this.forms.solutionForm.pid = this.forms.problemForm.pid = this.settings.problem.pid = fun.getUrlKey("pid");
            if (this.forms.problemForm.pid == null) window.location.href = "/problemset.html"
            var _this = this
            window.axios.all([_this.searchProblem()])
                .then(window.axios.spread((ProblemRes) => {
                    let ProblemData = ProblemRes.data;
                    _this.result.problemForm.problem = ProblemData.OJ_PROBLEM;
                    let error_type = ProblemData.OJ_ERROR_TYPE;
                    if (error_type == _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        _this.settings.base.beforeLoad = false;
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_NON_EXISTENT_PROBLEM) {
                        window.location.href = '/problemset.html';
                    }else if (error_type == _this.GLOBAL.OJ_ERROR_NOT_LOGIN) {
                        window.location.href = '/loginpage.html';
                    }
                    document.title = _this.result.problemForm.problem.title + " | CTGUACM";
                    $(document).ready(function () {
                        $(".double-card").each(function () {
                            let height1 = $(this).children(".card:first").children(".card-body").height();
                            let height2 = $(this).children(".card:last").children(".card-body").height();
                            let max_height;
                            if (height1 > height2) max_height = height1;
                            else max_height = height2;
                            $(this).children(".card:first").children(".card-body").css("height", (max_height + 25) + "px");
                            $(this).children(".card:last").children(".card-body").css("height", (max_height + 25) + "px");
                        });
                        var $moux = "49%";
                        $("middle-slider").mousedown(function () {
                            $("slide-curtain").fadeIn(0);
                            $("slide-curtain").mousemove(function (e) {
                                if (e.pageX <= window.innerWidth * 0.9 && e.pageX >= window.innerWidth * 0.4) {
                                    $moux = e.pageX - 0.0035 * window.innerWidth;
                                }
                                else if (e.pageX > window.innerWidth * 0.9) {
                                    $moux = window.innerWidth * 0.9 - 0.0035 * window.innerWidth;
                                }
                                else {
                                    $moux = window.innerWidth * 0.4 - 0.0035 * window.innerWidth;
                                }
                                var $leftlen = $moux / window.innerWidth * 100;
                                var $rightlen = (window.innerWidth * (1 - 0.0035) - $moux) / window.innerWidth * 100;

                                $("left-side").css("width", $leftlen + "vw");
                                $("right-side").css("width", $rightlen + "vw");

                            });
                        });
                        $("slide-curtain").mouseup(function () {
                            $("slide-curtain").fadeOut(0);
                            console.log($moux);

                        });
